/**
 * Dimensiones del bloque Sidebar — en un módulo PLANO (sin "use client") para
 * que los Server Components (catálogo /blocks, páginas de bloque) puedan importar
 * estas constantes. Importar valores desde un módulo "use client" hacia un Server
 * Component devuelve undefined → NaN en los cálculos de escala.
 */

export const SIDEBAR_WIDTH = 226;
export const SIDEBAR_HEIGHT = 1171;
export const SIDEBAR_COLLAPSED_WIDTH = 76; // solo iconos

"use client";

/**
 * Sidebar — Bloque de navegación lateral (Voyager DS)
 * Fuente: Figma VOYAGER · "SideBarDefault" (226×1042)
 *
 * Estructura:
 *   ┌──────────────────────────────┐ ← y=0
 *   │  SidebarHeader  (60px)       │
 *   ├──────────────────────────────┤ ← y=60   ← borde VYStrokes1
 *   │  Nav primary items (4)       │
 *   │  ─── separator ───           │
 *   │  Nav secondary items (1)     │
 *   │                              │
 *   │   ┌──────────────────────┐   │
 *   │   │  SidebarBanner 200×264│  │
 *   │   └──────────────────────┘   │
 *   └──────────────────────────────┘ ← y=1042
 */

import { useState } from "react";
import type { JSX, ReactNode } from "react";
import SidebarHeader from "./SidebarHeader";
import SidebarBanner from "./SidebarBanner";
import SidebarItem, { SidebarSeparator, type SidebarNavItem } from "./SidebarItem";
import TodayIcon from "@/concorde/components/TodayIcon";
import OfferIcon from "@/concorde/components/OfferIcon";
import CategoryIcon from "@/concorde/components/CategoryIcon";
import BusinessIcon from "@/concorde/components/BusinessIcon";
import ServiceCenterIcon from "@/concorde/components/ServiceCenterIcon";

// Dimensiones en un módulo plano (no-client) para que los Server Components puedan
// importarlas sin obtener undefined. Se re-exportan para los consumidores cliente.
export { SIDEBAR_WIDTH, SIDEBAR_HEIGHT, SIDEBAR_COLLAPSED_WIDTH } from "./dimensions";
import { SIDEBAR_WIDTH, SIDEBAR_HEIGHT, SIDEBAR_COLLAPSED_WIDTH } from "./dimensions";

const EASE = "cubic-bezier(0.4,0,0.2,1)";

const DEFAULT_PRIMARY: SidebarNavItem[] = [
  { id: "hoy",       icon: (s) => <TodayIcon        size={22} state={s} />, label: "Hoy" },
  {
    id: "oferta",    icon: (s) => <OfferIcon         size={22} state={s} />, label: "Tipo de oferta",  count: 2,
    subitems: [
      { id: "en-vivo",    label: "En Vivo",    count: 38 },
      { id: "negociable", label: "Negociable" },
    ],
  },
  { id: "categoria", icon: (s) => <CategoryIcon      size={22} state={s} />, label: "Categoría",       count: 2 },
  { id: "empresas",  icon: (s) => <BusinessIcon      size={22} state={s} />, label: "Empresas",        count: 2 },
];

const DEFAULT_SECONDARY: SidebarNavItem[] = [
  { id: "centro",    icon: (s) => <ServiceCenterIcon size={22} state={s} />, label: "Centro de Ayuda" },
];

const STYLE_ID = "concorde-sidebar-styles";
const STYLES = `
.sb-root {
  transition: width 0.28s ${EASE}, height 0.28s ${EASE};
}
.sb-content-frame {
  border: 1.5px solid transparent;
  /* Borde VYStrokes1 — dirección exacta del SVG (paint20: vector 283.9,21.1 → 94deg) */
  background:
    linear-gradient(#2E0F70, #2E0F70) padding-box,
    linear-gradient(94deg, #FFFFFF 0%, #F4AC59 22.1%, #8460E5 74.5%, #FFFFFF 100%) border-box;
  transition: width 0.28s ${EASE};
}
.sb-banner {
  display: flex;
  justify-content: center;
  padding: 0 7px 4px;
  opacity: 1;
  max-height: 280px;
  overflow: hidden;
  transition: opacity 0.18s ease, max-height 0.28s ${EASE}, padding 0.28s ${EASE};
}
.sb-banner--collapsed {
  opacity: 0;
  max-height: 0;
  padding: 0;
  pointer-events: none;
}
@media (prefers-reduced-motion: reduce) {
  .sb-root, .sb-content-frame, .sb-banner { transition: none; }
}
`;

let _injected = false;

export type { SidebarNavItem };

export interface SidebarProps {
  logo?: ReactNode;
  primaryItems?: SidebarNavItem[];
  secondaryItems?: SidebarNavItem[];
  defaultActiveId?: string;
  /** Alto del sidebar. Por defecto SIDEBAR_HEIGHT; pásale el alto del canvas
   *  cuando el contenido a la derecha sea más alto, para que crezca con él. */
  height?: number | string;
  /** Alto del bloque interno fijo (header + nav + banner). Por defecto
   *  SIDEBAR_HEIGHT (igual que siempre: si `height` es mayor, el sobrante
   *  queda como relleno morado plano debajo, sin estirar nav/banner).
   *  Edítalo SOLO cuando el contenido de al lado sea más CORTO que el
   *  sidebar — pásale ese mismo alto (igual a `height`) para que el spacer
   *  interno se comprima y el sidebar no sobre por debajo del contenido. */
  contentHeight?: number;
  /** Alto de la cabecera fija (logo + hamburguesa), en px. Por defecto 60. Cuando
   *  el contenido de al lado tiene su propio header y se escala, pásale la altura
   *  de ESE header escalada (p.ej. HEADER_HEIGHT × scale) para que el top de los
   *  iconos del sidebar quede alineado con el top del contenido. */
  headerHeight?: number;
  /** Colapsado (controlado). Si se omite, el Sidebar maneja su estado interno. */
  collapsed?: boolean;
  /** Callback al alternar el colapsado (para reaccionar desde el contenedor). */
  onCollapsedChange?: (collapsed: boolean) => void;
  onItemClick?: (id: string) => void;
  onBannerCta?: () => void;
}

export default function Sidebar({
  logo,
  primaryItems  = DEFAULT_PRIMARY,
  secondaryItems = DEFAULT_SECONDARY,
  defaultActiveId,
  height = SIDEBAR_HEIGHT,
  contentHeight = SIDEBAR_HEIGHT,
  headerHeight = 60,
  collapsed: collapsedProp,
  onCollapsedChange,
  onItemClick,
  onBannerCta,
}: SidebarProps): JSX.Element {
  const [internalCollapsed, setInternalCollapsed] = useState(false);
  const collapsed = collapsedProp ?? internalCollapsed;
  const [activeId,  setActiveId]  = useState(defaultActiveId);

  function toggleCollapsed(): void {
    const next = !collapsed;
    if (collapsedProp === undefined) setInternalCollapsed(next);
    onCollapsedChange?.(next);
  }

  if (typeof document !== "undefined" && !_injected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = STYLES;
      document.head.appendChild(el);
    }
    _injected = true;
  }

  function handleItemClick(id: string) {
    setActiveId(id);
    onItemClick?.(id);
  }

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: STYLES }} />
      <div
        data-slot="sidebar"
        className="sb-root"
        style={{
          width:         collapsed ? SIDEBAR_COLLAPSED_WIDTH : SIDEBAR_WIDTH,
          height,
          background:    "#2E0F70",
          fontFamily:    'var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif)',
          flexShrink:    0,
          position:      "relative",
          /* Sin overflow:hidden en la raíz — la cabecera (logo+hamburguesa) se
             mantiene a 226px aunque el resto colapse a 76px. */
        }}
      >
        {/* Cabecera FIJA (logo + hamburguesa) — ancho completo 226, no colapsa.
            Va como overlay en el top; el bloque de contenido de abajo deja headerHeight px. */}
        <div
          style={{
            position:  "absolute",
            top:       0,
            left:      0,
            width:     SIDEBAR_WIDTH,
            height:    headerHeight,
            zIndex:    2,
            background: "#2E0F70",
          }}
        >
          <SidebarHeader logo={logo} collapsed={collapsed} onToggle={toggleCollapsed} height={headerHeight} />
        </div>

        {/* Bloque colapsable (nav + banner) — este SÍ encoge su ancho. Recortado
            con overflow:hidden y desplazado headerHeight px para no tapar la cabecera. */}
        <div
          style={{
            height:        contentHeight,
            width:         collapsed ? SIDEBAR_COLLAPSED_WIDTH : SIDEBAR_WIDTH,
            paddingTop:    headerHeight,
            boxSizing:     "border-box",
            flexShrink:    0,
            display:       "flex",
            flexDirection: "column",
            overflow:      "hidden",
            transition:    `width 0.28s ${EASE}`,
          }}
        >
        {/* Área de contenido 216×935 — borde VYStrokes1 */}
        <div
          className="sb-content-frame"
          style={{
            width:         collapsed ? SIDEBAR_COLLAPSED_WIDTH - 10 : 216,
            flex:          1,
            margin:        "0 5px 47px",
            display:       "flex",
            flexDirection: "column",
            overflow:      "hidden",
            borderRadius:  17,
          }}
        >
          {/* Nav items */}
          <nav
            aria-label="Navegación principal"
            style={{ padding: 0, display: "flex", flexDirection: "column", gap: 6 }}
          >
            {primaryItems.map((item) => (
              <SidebarItem
                key={item.id}
                {...item}
                isActive={activeId === item.id}
                collapsed={collapsed}
                onClick={handleItemClick}
              />
            ))}

            {secondaryItems.length > 0 && <SidebarSeparator />}

            {secondaryItems.map((item) => (
              <SidebarItem
                key={item.id}
                {...item}
                isActive={activeId === item.id}
                collapsed={collapsed}
                onClick={handleItemClick}
              />
            ))}
          </nav>

          {/* Spacer */}
          <div style={{ flex: 1 }} />

          {/* Banner inferior 200×264 */}
          <div className={`sb-banner${collapsed ? " sb-banner--collapsed" : ""}`}>
            <SidebarBanner onCta={onBannerCta} />
          </div>
        </div>
        </div>
      </div>
    </>
  );
}

"use client";

/**
 * SidebarBanner — 200×264 · banner CTA inferior del sidebar
 * Fuente: Figma VOYAGER · "SideBarDefault" — frame inferior (paint18 + paint19)
 *
 * Fondo: gradiente vertical #3B1A7A → #3B1782 → #6E3E2A
 * Botón CTA: gradiente vertical #F5921E → #E15F2B, pill de 31px
 */

import type { JSX } from "react";

export const BANNER_W = 200;
export const BANNER_H = 264;

export interface SidebarBannerProps {
  onCta?: () => void;
}

export default function SidebarBanner({ onCta: _ }: SidebarBannerProps): JSX.Element {
  return (
    <div
      data-slot="sidebar-banner"
      style={{
        width:           BANNER_W,
        height:          BANNER_H,
        borderRadius:    16,
        background:      "rgba(255,255,255,0.07)",
        flexShrink:      0,
        display:         "flex",
        alignItems:      "center",
        justifyContent:  "center",
      }}
    >
      <span
        style={{
          fontSize:      10,
          fontWeight:    600,
          letterSpacing: "0.12em",
          textTransform: "uppercase",
          color:         "rgba(255,255,255,0.25)",
        }}
      >
        Banner
      </span>
    </div>
  );
}

"use client";

/**
 * SidebarHeader — 226×60 · logo + botón colapsar
 * Fuente: Figma VOYAGER · "SideBarDefault" (header superior)
 * Icono hamburguesa: 3 líneas con gradiente CFBAFF→white→AE8EFF→CFBAFF
 */

import { useId } from "react";
import type { JSX, ReactNode } from "react";

const STYLE_ID = "concorde-sbheader-styles";
const STYLES = `
.psb-toggle {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  padding: 0;
  border: none;
  background: transparent;
  cursor: pointer;
  border-radius: 8px;
  flex-shrink: 0;
  transition: background 0.15s;
}
.psb-toggle:hover { background: rgba(255,255,255,0.08); }
.psb-toggle:active { background: rgba(255,255,255,0.14); }
.psb-toggle:focus-visible { outline: 2px solid #8460E5; outline-offset: 2px; }
.sbh-logo {
  flex: 1;
  display: flex;
  align-items: center;
  gap: 8px;
  min-width: 0;
  /* El logo permanece SIEMPRE visible (también al colapsar): no se desvanece,
     solo lo recorta el overflow del sidebar (76px) mostrando el isotipo. */
  overflow: visible;
  opacity: 1;
}
@media (prefers-reduced-motion: reduce) {
  .psb-toggle, .sbh-logo { transition: none; }
}
`;

let _injected = false;

export interface SidebarHeaderProps {
  /** Slot para el logo de la aplicación */
  logo?: ReactNode;
  /** Estado colapsado del sidebar */
  collapsed?: boolean;
  /** Handler del botón hamburguesa */
  onToggle?: () => void;
  /** Alto de la cabecera en px (para alinear con el header del contenido). Default 60. */
  height?: number;
}

export default function SidebarHeader({ logo, collapsed = false, onToggle, height = 60 }: SidebarHeaderProps): JSX.Element {
  const uid = useId().replace(/:/g, "-");

  if (typeof document !== "undefined" && !_injected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = STYLES;
      document.head.appendChild(el);
    }
    _injected = true;
  }

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: STYLES }} />
      <div
        data-slot="sidebar-header"
        style={{
          width: "100%",
          height,
          display: "flex",
          alignItems: "center",
          // La hamburguesa queda alineada con la columna de iconos del sidebar
          // colapsado (centro ≈ 38px): paddingLeft 20 + medio botón (18) = 38.
          paddingLeft: 20,
          paddingRight: 14,
          gap: 8,
          flexShrink: 0,
          boxSizing: "border-box",
        }}
      >
        {/* Botón colapsar */}
        <button
          type="button"
          className="psb-toggle"
          onClick={onToggle}
          aria-label={collapsed ? "Expandir menú" : "Colapsar menú"}
          aria-expanded={!collapsed}
        >
          <svg
            width="22"
            height="22"
            viewBox="0 0 22 22"
            fill="none"
            xmlns="http://www.w3.org/2000/svg"
            aria-hidden="true"
          >
            <path d="M2.75 5.5H19.25"  stroke={`url(#${uid}g0)`} strokeWidth="1.83333" strokeLinecap="round"/>
            <path d="M2.75 11H19.25"   stroke={`url(#${uid}g1)`} strokeWidth="1.83333" strokeLinecap="round"/>
            <path d="M2.75 16.5H19.25" stroke={`url(#${uid}g2)`} strokeWidth="1.83333" strokeLinecap="round"/>
            <defs>
              <linearGradient id={`${uid}g0`} x1="5.708" y1="4.866"  x2="6.637" y2="9.202"  gradientUnits="userSpaceOnUse">
                <stop stopColor="#CFBAFF"/><stop offset="0.35" stopColor="white"/>
                <stop offset="0.65" stopColor="#AE8EFF"/><stop offset="1" stopColor="#CFBAFF"/>
              </linearGradient>
              <linearGradient id={`${uid}g1`} x1="5.708" y1="10.366" x2="6.637" y2="14.702" gradientUnits="userSpaceOnUse">
                <stop stopColor="#CFBAFF"/><stop offset="0.35" stopColor="white"/>
                <stop offset="0.65" stopColor="#AE8EFF"/><stop offset="1" stopColor="#CFBAFF"/>
              </linearGradient>
              <linearGradient id={`${uid}g2`} x1="5.708" y1="15.866" x2="6.637" y2="20.202" gradientUnits="userSpaceOnUse">
                <stop stopColor="#CFBAFF"/><stop offset="0.35" stopColor="white"/>
                <stop offset="0.65" stopColor="#AE8EFF"/><stop offset="1" stopColor="#CFBAFF"/>
              </linearGradient>
            </defs>
          </svg>
        </button>

        {/* Slot del logo — visible siempre (no desaparece al colapsar) */}
        <div className="sbh-logo">
          {logo ?? (
            // eslint-disable-next-line @next/next/no-img-element
            <img
              src="/assets/brand/logo-voyager.svg"
              alt="VMC Subastas"
              style={{ height: 40, width: "auto", display: "block", flexShrink: 0 }}
            />
          )}
        </div>
      </div>
    </>
  );
}

"use client";

/**
 * SidebarItem — nav pill 216×48 del sidebar
 * Fuente: Figma VOYAGER · "SideBarDefault" — State=Default/Hover/Active SVGs
 *
 * Estados del pill:
 *   default — glass gradient + subtle white border + shadow morado
 *   hover   — fondo #8460E5 38% + borde blanco 44%
 *   active  — naranja gradient + VYStrokes1 border + orange glow
 *
 * Subitems: expanden abajo con animación max-height cuando isActive=true y hay subitems
 */

import { useId, useState } from "react";
import type { JSX, ReactNode } from "react";
import SidebarSubItem, { type SidebarSubItemDef } from "./SidebarSubItem";

const STYLE_ID = "concorde-sbi-styles";
const STYLES = `
.sbi-item {
  width: 100%;
  height: 48px;
  border-radius: 16px;
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 0 14px;
  box-sizing: border-box;
  cursor: pointer;
  user-select: none;
  outline: none;
  border: 1.5px solid transparent;
  /* Glass fill (paint0: white 0.28 → 0.1 → 0.04) sobre base oscura #0A002E (simula
     el "behind transparent areas" de Figma: la sombra se ve a través del glass) +
     borde VYStrokes3 (white 0.1 → 0 @55%) */
  background:
    linear-gradient(105deg, rgba(255,255,255,0.28) 0%, rgba(255,255,255,0.10) 40%, rgba(255,255,255,0.04) 100%) padding-box,
    linear-gradient(rgba(10,0,46,0.34), rgba(10,0,46,0.34)) padding-box,
    linear-gradient(180deg, rgba(255,255,255,0.10) 0%, rgba(255,255,255,0) 55%) border-box;
  -webkit-backdrop-filter: blur(20px);
  backdrop-filter: blur(20px);
  /* Drop #0A002E (0,12,36,-4) reforzado + inner top white 22% + inner bottom black 30% */
  box-shadow:
    0px 12px 36px -4px rgba(10,0,46,0.7),
    0px 4px 14px -2px rgba(10,0,46,0.5),
    inset 0px 1px 0px rgba(255,255,255,0.22),
    inset 0px -1px 6px rgba(0,0,0,0.3);
  transition: box-shadow 0.15s, background 0.12s, border-color 0.12s, padding 0.28s cubic-bezier(0.4,0,0.2,1), gap 0.28s cubic-bezier(0.4,0,0.2,1);
}
.sbi-item--collapsed {
  padding: 0;
  gap: 0;
  justify-content: center;
}
/* Hover — fill #8460E5 38% (sobre base oscura) + borde white 44% + drop #0A0026 55%
   (0,6,18,-6) + inner top white 60% (0,1,4) */
.sbi-item--hover {
  border: 1px solid rgba(255,255,255,0.44);
  background:
    rgba(132,96,229,0.38) padding-box,
    linear-gradient(rgba(10,0,38,0.32), rgba(10,0,38,0.32)) padding-box;
  box-shadow:
    0px 6px 18px -6px rgba(10,0,38,0.55),
    inset 0px 1px 4px rgba(255,255,255,0.6);
}
/* Pressed/Active — VYGradientOrange1 + borde gradiente + drop #ED8936 (0,2,25,-2)
   + background blur 10 */
.sbi-item--active {
  border: 1.5px solid transparent;
  background:
    linear-gradient(180deg, #FF9639 0%, #EF852E 40%, #BE3D00 100%) padding-box,
    linear-gradient(143deg, #FFFFFF 0%, #F4AC59 22.1%, #8460E5 74.5%, #FFFFFF 100%) border-box;
  -webkit-backdrop-filter: blur(10px);
  backdrop-filter: blur(10px);
  box-shadow: 0px 2px 25px -2px rgba(237,137,54,0.55);
}
.sbi-item:focus-visible {
  outline: 2px solid rgba(255,255,255,0.5);
  outline-offset: 2px;
}
.sbi-trailing {
  flex: 1;
  display: flex;
  align-items: center;
  gap: 10px;
  min-width: 0;
  overflow: hidden;
  opacity: 1;
  max-width: 200px;
  transition: opacity 0.18s ease, max-width 0.28s cubic-bezier(0.4,0,0.2,1);
}
.sbi-item--collapsed .sbi-trailing {
  opacity: 0;
  max-width: 0;
  flex: 0;
}
.sbi-label {
  flex: 1;
  font-size: 14px;
  font-weight: 600;
  letter-spacing: -0.01em;
  color: #D1D5DC;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  min-width: 0;
}
.sbi-item--active .sbi-label {
  color: #FFFFFF;
}
.sbi-sep {
  height: 1px;
  background: rgba(255,255,255,0.4);
  margin: 4px 14px;
  flex-shrink: 0;
}
.sbi-subitems {
  overflow: hidden;
  max-height: 0;
  opacity: 0;
  display: flex;
  flex-direction: column;
  gap: 4px;
  padding: 0 0 0 8px;
  margin-top: 0;
  transition: max-height 0.25s ease, opacity 0.2s ease, margin-top 0.2s ease;
}
.sbi-subitems--open {
  max-height: 400px;
  opacity: 1;
  margin-top: 4px;
}
@media (prefers-reduced-motion: reduce) {
  .sbi-item, .sbi-subitems { transition: none; }
}
`;

let _injected = false;

// ── Tipos públicos ────────────────────────────────────────────────────────────

export interface SidebarNavItem {
  id: string;
  /** Función que recibe el estado visual y retorna el icono correspondiente */
  icon: (state: "default" | "hover" | "active") => ReactNode;
  label: string;
  /** Número mostrado en el badge circular (normalmente = subitems.length) */
  count?: number;
  /** Subitems expandibles — diseño passed via props */
  subitems?: SidebarSubItemDef[];
}

interface SidebarItemProps extends SidebarNavItem {
  isActive?: boolean;
  collapsed?: boolean;
  onClick?: (id: string) => void;
}

// ── Badge de conteo ───────────────────────────────────────────────────────────

function SidebarBadge({ count, active, uid }: { count: number; active: boolean; uid: string }): JSX.Element {
  return (
    <svg width={22} height={22} viewBox="0 0 22 22" fill="none" style={{ flexShrink: 0 }} aria-hidden="true">
      <defs>
        <linearGradient id={`${uid}bd`} x1="3.73" y1="-11.55" x2="30.06" y2="-3.04" gradientUnits="userSpaceOnUse">
          <stop stopColor="white"/>
          <stop offset="0.221154" stopColor="#F4AC59"/>
          <stop offset="0.745192" stopColor="#8460E5"/>
          <stop offset="1" stopColor="white"/>
        </linearGradient>
        {active && (
          <linearGradient id={`${uid}bn`} x1="11" y1="6" x2="11" y2="16" gradientUnits="userSpaceOnUse">
            <stop stopColor="#FF9639"/>
            <stop offset="0.5" stopColor="#EF852E"/>
            <stop offset="1" stopColor="#BE3D00"/>
          </linearGradient>
        )}
      </defs>
      <circle
        cx="11" cy="11" r="10.5"
        fill={active ? "white" : "rgba(34,0,92,0.10)"}
        stroke={`url(#${uid}bd)`}
      />
      <text
        x="11" y="15.2"
        textAnchor="middle"
        fontSize="10"
        fontWeight="600"
        fill={active ? `url(#${uid}bn)` : "white"}
        fontFamily="inherit"
      >
        {count}
